# ── WHY THIS FILE ────────────────────────────────────────────────────────────
# Specific exception types so every public call has a defined, named failure.
# 🎙️ "I never raise bare Exception — each boundary failure has its own type so
#      callers can catch exactly what they expect."


class BrokerError(Exception):
    """Base class for everything this broker can refuse to do."""


class UnknownTopicError(BrokerError):
    """Publish/subscribe to a topic that was never created."""


class TopicExistsError(BrokerError):
    """create_topic called twice with the same name."""


class UnknownSubscriberError(BrokerError):
    """Operation referencing a subscriber id that was never registered."""


class NotSubscribedError(BrokerError):
    """poll/reset on a topic this subscriber never subscribed to."""


class InvalidOffsetError(BrokerError):
    """Reset target is outside [0, len(log)]."""

from __future__ import annotations

from abc import ABC, abstractmethod
from bisect import bisect_left
from datetime import datetime
from typing import List

from models import Message


# ── WHY THIS CLASS ──────────────────────────────────────────────────────────
# The replay seam. "Reset my offset" has several real policies (Kafka's
# auto.offset.reset = earliest/latest, plus seek-to-offset and seek-to-time).
# The broker depends on THIS interface, not on a big if/else.
# 🎙️ "Offset reset is a Strategy. The broker just calls resolve(log) and validates
#      the number it gets back. New reset policies are new classes, nothing else."
class OffsetResetStrategy(ABC):
    @abstractmethod
    def resolve(self, log: List[Message]) -> int:
        """Return the target offset for this reset policy."""


class ToEarliest(OffsetResetStrategy):
    """Replay the whole topic from the very first message."""
    def resolve(self, log: List[Message]) -> int:
        return 0


class ToLatest(OffsetResetStrategy):
    """Skip to the end — only see messages published from now on."""
    def resolve(self, log: List[Message]) -> int:
        return len(log)


class ToOffset(OffsetResetStrategy):
    """Seek to an exact offset (the broker range-checks the result)."""
    def __init__(self, target: int) -> None:
        self.target = target

    def resolve(self, log: List[Message]) -> int:
        return self.target


class ToTimestamp(OffsetResetStrategy):
    """Seek to the first message at or after a wall-clock time."""
    def __init__(self, ts: datetime) -> None:
        self.ts = ts

    def resolve(self, log: List[Message]) -> int:
        # WHY: the log is append-ordered, so timestamps are non-decreasing and we
        #      can binary-search instead of scanning. O(log n) not O(n).
        # ⚠️ FOLLOW-UP: "Why is binary search safe here?"
        #    -> "Messages are appended in time order, so the timestamp column is
        #        already sorted. bisect finds the first one >= the target time."
        times = [m.timestamp for m in log]
        return bisect_left(times, self.ts)
